-- 7. PHIẾU BÁN HÀNG (HEADER)
-- ─────────────────────────────────────────

-- ─────────────────────────────────────────
-- 8. DÒNG HÀNG HÓA
-- ─────────────────────────────────────────

-- ─────────────────────────────────────────
-- 9. FACT TABLE (sinh từ JOIN)
-- ─────────────────────────────────────────
    order_date, fiscal_year, fiscal_quarter, fiscal_month, week_of_year,
    so_number, order_id, line_id,
    customer_code, customer_name, province_id, province_name, region,
    product_code, product_name, color, line_id_fk, line_name, group_code, group_name,
    quantity, unit_price, line_total
)
SELECT
    so.order_date,
    so.fiscal_year,
    so.fiscal_quarter,
    so.fiscal_month,
    EXTRACT(WEEK FROM so.order_date)::SMALLINT   AS week_of_year,
    ol.so_number,
    so.order_id,
    ol.line_id,
    c.customer_code,
    c.customer_name,
    c.province_id,
    pr.province_name,
    pr.region,
    p.product_code,
    p.product_name,
    p.color,
    p.line_id                                    AS line_id_fk,
    pl.line_name,
    pg.group_code,
    pg.group_name,
    ol.quantity,
    ol.unit_price,
    ol.line_total
FROM order_line ol
JOIN sales_order  so ON so.order_id      = ol.order_id
JOIN customer     c  ON c.customer_code  = so.customer_code
JOIN product      p  ON p.product_code   = ol.product_code
LEFT JOIN product_line  pl ON pl.line_id   = p.line_id
LEFT JOIN product_group pg ON pg.group_code = pl.group_code
LEFT JOIN province      pr ON pr.province_id = c.province_id;


COMMIT;

-- ─────────────────────────────────────────
-- Kiểm tra sau import
-- ─────────────────────────────────────────
SELECT 'product_group'  AS tbl, COUNT(*) AS rows FROM product_group  UNION ALL
SELECT 'product_line',              COUNT(*) FROM product_line             UNION ALL
SELECT 'product',                   COUNT(*) FROM product                  UNION ALL
SELECT 'product_price',             COUNT(*) FROM product_price            UNION ALL
SELECT 'province',                  COUNT(*) FROM province                 UNION ALL
SELECT 'customer',                  COUNT(*) FROM customer                 UNION ALL
SELECT 'sales_order',               COUNT(*) FROM sales_order              UNION ALL
SELECT 'order_line',                COUNT(*) FROM order_line               UNION ALL
SELECT 'fact_sales',                COUNT(*) FROM fact_sales
ORDER BY 1;